import java.sql.*; public class DBDump { public static void main(String[] args) throws Exception { Connection conn = DriverManager.getConnection("jdbc:sqlite:ALIP.db"); Statement stmt = conn.createStatement(); ResultSet rs = stmt.executeQuery("SELECT s.student_id, s.name, sub.subject_name, sc.score FROM students s LEFT JOIN student_scores sc ON s.id = sc.student_id LEFT JOIN subjects sub ON sc.subject_id = sub.id"); while (rs.next()) { System.out.println(rs.getString("student_id") + " | " + rs.getString("name") + " | " + rs.getString("subject_name") + " | " + rs.getDouble("score")); } rs.close(); stmt.close(); conn.close(); } }
